export function getCityBySlug(stateSlug: string, citySlug: string): City | undefined {
  return CITIES.find(c => c.stateSlug === stateSlug && c.slug === citySlug);
}

export function getCitiesByState(stateSlug: string): City[] {
  return CITIES.filter(c => c.stateSlug === stateSlug);
}

export function getStates(): { state: string; stateSlug: string; stateAbbr: string; cityCount: number }[] {
  const map = new Map<string, { state: string; stateSlug: string; stateAbbr: string; cityCount: number }>();
  for (const c of CITIES) {
    if (!map.has(c.stateSlug)) {
      map.set(c.stateSlug, { state: c.state, stateSlug: c.stateSlug, stateAbbr: c.stateAbbr, cityCount: 0 });
    }
    map.get(c.stateSlug)!.cityCount++;
  }
  return Array.from(map.values()).sort((a, b) => a.state.localeCompare(b.state));
}
